import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { LoginForm } from './LoginForm';

describe('LoginForm', () => {
  // Chạy trước MỖI test trong describe này
  beforeEach(() => {
    // Reset mocks nếu cần
    jest.clearAllMocks();
  });

  describe('khi form trống', () => {
    it('hiển thị placeholder trong các input', () => {
      render(<LoginForm />);
      expect(screen.getByLabelText('Email')).toHaveValue('');
      expect(screen.getByLabelText('Mật khẩu')).toHaveValue('');
    });

    it('nút đăng nhập bị disabled', () => {
      render(<LoginForm />);
      expect(screen.getByRole('button', { name: /đăng nhập/i })).toBeDisabled();
    });
  });

  describe('khi nhập email hợp lệ', () => {
    it('cho phép submit', async () => {
      const user = userEvent.setup();
      render(<LoginForm />);
      await user.type(screen.getByLabelText('Email'), 'a@b.com');
      await user.type(screen.getByLabelText('Mật khẩu'), '123456');
      expect(screen.getByRole('button', { name: /đăng nhập/i })).toBeEnabled();
    });
  });
});

import { render, screen } from '@testing-library/react';

test('hiển thị greeting theo tên', () => {
  // 1. Render
  const { rerender } = render(<Greeting name="An" />);

  // 2. Query + Assert
  expect(screen.getByText('Xin chào, An!')).toBeInTheDocument();

  // 3. In DOM để debug khi bí
  // screen.debug(); // → <div>Xin chào, An!</div>

  // 4. Rerender với props mới — không remount
  rerender(<Greeting name="Bình" />);
  expect(screen.getByText('Xin chào, Bình!')).toBeInTheDocument();
  expect(screen.queryByText('Xin chào, An!')).not.toBeInTheDocument();
});

