// Component cần test
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`/api/users/${userId}`)
      .then(r => r.json())
      .then(data => { setUser(data); setLoading(false); });
  }, [userId]);

  if (loading) return <div role="progressbar">Đang tải...</div>;
  return <div>{user.name}</div>;
}

// Test với mock fetch
beforeEach(() => {
  global.fetch = jest.fn().mockResolvedValue({
    json: () => Promise.resolve({ name: 'Nguyễn Văn An' }),
  });
});

test('hiển thị loading rồi user name', async () => {
  render(<UserProfile userId="1" />);

  // Kiểm tra loading state
  expect(screen.getByRole('progressbar')).toBeInTheDocument();

  // Chờ data load xong
  const name = await screen.findByText('Nguyễn Văn An');
  expect(name).toBeInTheDocument();
  expect(screen.queryByRole('progressbar')).not.toBeInTheDocument();
});
